class Solution {
    public int strongPasswordChecker(String password) {
        int n = password.length();
        int[] cnt = new int[128];
        int upper = 0, lower = 0, digit = 0, repeat = 0;
        for (char c : password.toCharArray()) {
            if (Character.isUpperCase(c)) upper++;
            else if (Character.isLowerCase(c)) lower++;
            else if (Character.isDigit(c)) digit++;
            cnt[c]++;
            if (cnt[c] == 3) repeat++;
        }
        int remove = Math.max(0, n - 20);
        int insert = Math.max(6 - n, 0);
        int replace = repeat;
        if (n < 20) {
            for (int i = 1; i < n; i++) {
                if (password.charAt(i) == password.charAt(i - 1) && password.charAt(i) == password.charAt(i + 1)) repeat--;
            }
        }
        if (n >= 20) {
            int groups = n / 3;
            replace = Math.max(replace, groups - (n - 20));
        }
        return Math.max(remove + insert, replace);
    }
}
